class Rectangle:
    def __init__(self, w, h):
        self.width = w
        self.height = h

    @property
    def area(self):
        return self.width * self.height

r = Rectangle(4, 5)
print(r.area)       # No () needed
r.width = 10
print(r.area)       # Automatically recomputed
